// Find the earliest Friday the 13th in the proleptic Gregorian calendar
// and count all Friday the 13ths in a full 400-year cycle.

// Earliest Friday the 13th starting from 0001-01-01
DateOnly date = new DateOnly(1, 1, 13);
while (date.DayOfWeek != DayOfWeek.Friday)
{
    date = date.AddMonths(1);
}
Console.WriteLine($"Earliest Friday the 13th: {date:yyyy-MM-dd} ({date.DayOfWeek})");

// Count Friday the 13ths in a full 400-year cycle (0001-01-01 to 0400-12-31)
int count = 0;
DateOnly current = new DateOnly(1, 1, 13);
DateOnly end = new DateOnly(400, 12, 13);

while (current <= end)
{
    if (current.DayOfWeek == DayOfWeek.Friday)
        count++;
    current = current.AddMonths(1);
}

Console.WriteLine($"Friday the 13ths in a 400-year cycle: {count}");
Console.WriteLine($"Average per year: {count / 400.0:F4}");
EOF
